SELECT COUNT(animal_id) AS healthy_animal_count
FROM animals
WHERE health_status = 'Healthy';

SELECT AVG(weight) AS average_weight_of_dogs
FROM animals
WHERE animal_type = 'Dog' AND spayed_neutered = 1;

SELECT AVG(STRFTIME('%Y', 'now') - STRFTIME('%Y', entry_date)) AS average_age
FROM animals
WHERE animal_type = 'Dog';

SELECT AVG(adoption_fee) AS average_adoption_fee
FROM adoption_applications
WHERE application_status = 'Approved' AND home_visit_date >= DATE('now', '-6 months');

SELECT a.name AS AnimalName, a.breed AS Breed
FROM animals a
WHERE a.breed = 'Golden Retriever';

SELECT AVG(weight) AS average_weight
FROM animals
WHERE breed = 'Golden Retriever' AND health_status = 'Healthy';

SELECT AVG(weight) AS average_weight
FROM animals
WHERE animal_type = 'Dog';

SELECT COUNT(DISTINCT aa.animal_id) AS total_adopted_animals
FROM adoption_applications aa
WHERE aa.application_status = 'Approved';

SELECT COUNT(*) AS adopted_animals_count
FROM outcomes
WHERE outcome_type = 'Adoption';

SELECT AVG(weight) AS average_weight
FROM animals
WHERE spayed_neutered = 1 AND health_status = 'Good';

SELECT outcome_type, COUNT(*) AS total_outcomes
FROM outcomes
GROUP BY outcome_type;

SELECT AVG(weight) AS average_cat_weight
FROM animals
WHERE animal_type = 'Cat' AND spayed_neutered = 1;
